// Mediator interface
class Mediator {
  notify(sender, event) {}
}

// Base component
class Component {
  setMediator(mediator) { this.mediator = mediator; }
}

class Checkbox extends Component {
  constructor(label) { super(); this.label = label; this.checked = false; }
  check() {
    this.checked = !this.checked;
    console.log(`Checkbox "${this.label}" -> ${this.checked}`);
    this.mediator.notify(this, 'toggle');
  }
}

class TextField extends Component {
  constructor(label) { super(); this.label = label; this.visible = true; }
  setVisible(visible) {
    this.visible = visible;
    console.log(`Field "${this.label}" ${visible ? 'shown' : 'hidden'}`);
  }
}

class Button extends Component {
  constructor(label) { super(); this.label = label; this.enabled = true; }
  setEnabled(enabled) {
    this.enabled = enabled;
    console.log(`Button "${this.label}" ${enabled ? 'enabled' : 'disabled'}`);
  }
}

// Concrete mediator
class AuthDialog extends Mediator {
  constructor() {
    super();
    this.guest = new Checkbox('Login as guest');
    this.username = new TextField('Username');
    this.submit = new Button('Submit');
    [this.guest, this.username, this.submit].forEach(c => c.setMediator(this));
  }

  notify(sender, event) {
    if (sender === this.guest && event === 'toggle') {
      this.username.setVisible(!this.guest.checked);
      this.submit.setEnabled(true);
    }
  }
}

// Usage
const dialog = new AuthDialog();

dialog.guest.check(); // Checkbox "Login as guest" -> true / Field "Username" hidden / Button "Submit" enabled
dialog.guest.check(); // Checkbox "Login as guest" -> false / Field "Username" shown / Button "Submit" enabled

