// Mediator interface
interface Mediator {
    void notify(Component sender, String event);
}

// Base component
abstract class Component {
    protected Mediator mediator;
    public void setMediator(Mediator m) { this.mediator = m; }
}

class Checkbox extends Component {
    private final String label;
    public boolean checked = false;

    Checkbox(String label) { this.label = label; }

    public void check() {
        checked = !checked;
        System.out.printf("Checkbox \"%s\" -> %b%n", label, checked);
        mediator.notify(this, "toggle");
    }
}

class TextField extends Component {
    private final String label;
    public boolean visible = true;

    TextField(String label) { this.label = label; }

    public void setVisible(boolean v) {
        visible = v;
        System.out.printf("Field \"%s\" %s%n", label, v ? "shown" : "hidden");
    }
}

class Button extends Component {
    private final String label;
    public boolean enabled = true;

    Button(String label) { this.label = label; }

    public void setEnabled(boolean e) {
        enabled = e;
        System.out.printf("Button \"%s\" %s%n", label, e ? "enabled" : "disabled");
    }
}

// Concrete mediator
class AuthDialog implements Mediator {
    final Checkbox  guest    = new Checkbox("Login as guest");
    final TextField username = new TextField("Username");
    final Button    submit   = new Button("Submit");

    AuthDialog() {
        for (Component c : new Component[]{guest, username, submit})
            c.setMediator(this);
    }

    public void notify(Component sender, String event) {
        if (sender == guest && "toggle".equals(event)) {
            username.setVisible(!guest.checked);
            submit.setEnabled(true);
        }
    }
}

// Usage
AuthDialog dialog = new AuthDialog();
dialog.guest.check(); // Checkbox "Login as guest" -> true / Field "Username" hidden / Button "Submit" enabled
dialog.guest.check(); // Checkbox "Login as guest" -> false / Field "Username" shown / Button "Submit" enabled

