// Mediator interface
interface IMediator { void Notify(Component sender, string @event); }

// Base component
abstract class Component
{
    protected IMediator Mediator = null!;
    public void SetMediator(IMediator m) => Mediator = m;
}

class Checkbox : Component
{
    private readonly string _label;
    public bool Checked { get; private set; }
    public Checkbox(string label) => _label = label;

    public void Check()
    {
        Checked = !Checked;
        Console.WriteLine($"Checkbox \"{_label}\" -> {Checked}");
        Mediator.Notify(this, "toggle");
    }
}

class TextField : Component
{
    private readonly string _label;
    public bool Visible { get; private set; } = true;
    public TextField(string label) => _label = label;

    public void SetVisible(bool v)
    {
        Visible = v;
        Console.WriteLine($"Field \"{_label}\" {(v ? "shown" : "hidden")}");
    }
}

class Button : Component
{
    private readonly string _label;
    public bool Enabled { get; private set; } = true;
    public Button(string label) => _label = label;

    public void SetEnabled(bool e)
    {
        Enabled = e;
        Console.WriteLine($"Button \"{_label}\" {(e ? "enabled" : "disabled")}");
    }
}

// Concrete mediator
class AuthDialog : IMediator
{
    public readonly Checkbox  Guest    = new("Login as guest");
    public readonly TextField Username = new("Username");
    public readonly Button    Submit   = new("Submit");

    public AuthDialog()
    {
        foreach (var c in new Component[] { Guest, Username, Submit })
            c.SetMediator(this);
    }

    public void Notify(Component sender, string @event)
    {
        if (sender == Guest && @event == "toggle")
        {
            Username.SetVisible(!Guest.Checked);
            Submit.SetEnabled(true);
        }
    }
}

// Usage
var dialog = new AuthDialog();
dialog.Guest.Check(); // Checkbox "Login as guest" -> True / Field "Username" hidden / Button "Submit" enabled
dialog.Guest.Check(); // Checkbox "Login as guest" -> False / Field "Username" shown / Button "Submit" enabled

