from __future__ import annotations
from abc import ABC, abstractmethod


class Mediator(ABC):
    @abstractmethod
    def notify(self, sender: Component, event: str) -> None: ...


class Component:
    def __init__(self) -> None:
        self.mediator: Mediator | None = None

    def set_mediator(self, mediator: Mediator) -> None:
        self.mediator = mediator


class Checkbox(Component):
    def __init__(self, label: str) -> None:
        super().__init__()
        self.label = label
        self.checked = False

    def check(self) -> None:
        self.checked = not self.checked
        print(f'Checkbox "{self.label}" -> {self.checked}')
        self.mediator.notify(self, 'toggle')


class TextField(Component):
    def __init__(self, label: str) -> None:
        super().__init__()
        self.label = label
        self.visible = True

    def set_visible(self, visible: bool) -> None:
        self.visible = visible
        print(f'Field "{self.label}" {"shown" if visible else "hidden"}')


class Button(Component):
    def __init__(self, label: str) -> None:
        super().__init__()
        self.label = label
        self.enabled = True

    def set_enabled(self, enabled: bool) -> None:
        self.enabled = enabled
        print(f'Button "{self.label}" {"enabled" if enabled else "disabled"}')


class AuthDialog(Mediator):
    def __init__(self) -> None:
        self.guest = Checkbox('Login as guest')
        self.username = TextField('Username')
        self.submit = Button('Submit')
        for component in (self.guest, self.username, self.submit):
            component.set_mediator(self)

    def notify(self, sender: Component, event: str) -> None:
        if sender is self.guest and event == 'toggle':
            self.username.set_visible(not self.guest.checked)
            self.submit.set_enabled(True)


# Usage
dialog = AuthDialog()

dialog.guest.check()  # Checkbox "Login as guest" -> True / Field "Username" hidden / Button "Submit" enabled
dialog.guest.check()  # Checkbox "Login as guest" -> False / Field "Username" shown / Button "Submit" enabled
